// NewListPluginsResponseBody builds the HTTP response body from the result of
// the "listPlugins" endpoint of the "plugins" service.
func NewListPluginsResponseBody(res *plugins.ListPluginsResult) *ListPluginsResponseBody {
	body := &ListPluginsResponseBody{}
	if res.Plugins != nil {
		body.Plugins = make([]*PluginResponseBody, len(res.Plugins))
		for i, val := range res.Plugins {
			if val == nil {
				body.Plugins[i] = nil
				continue
			}
			body.Plugins[i] = marshalPluginsPluginToPluginResponseBody(val)
		}
	} else {
		body.Plugins = []*PluginResponseBody{}
	}
	return body
}

